import { GoogleGenAI, Type, Schema } from "@google/genai";

// ================================================================
// TYPES
// ================================================================

interface CategoryResult {
  score: number;
  label: string;
  details: string;
  tips: string[];
}

export interface AnswerFirstAuditResult {
  globalScore: number; // 0-100
  url: string;
  categories: {
    answerFirst: CategoryResult;
    schemaOrg: CategoryResult;
    faqStructure: CategoryResult;
    semanticHtml: CategoryResult;
    contentFreshness: CategoryResult;
    metaOptimization: CategoryResult;
  };
  summary: string;
  topRecommendations: string[];
}

// ================================================================
// API KEY HELPER
// ================================================================

const getApiKey = () => {
  if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
    return process.env.API_KEY;
  }
  return null;
};

// ================================================================
// CATEGORY WEIGHTS
// ================================================================

const CATEGORY_WEIGHTS: Record<keyof AnswerFirstAuditResult['categories'], number> = {
  answerFirst: 0.25,
  schemaOrg: 0.20,
  faqStructure: 0.15,
  semanticHtml: 0.15,
  contentFreshness: 0.10,
  metaOptimization: 0.15,
};

// ================================================================
// WEIGHTED AVERAGE HELPER
// ================================================================

const computeGlobalScore = (categories: AnswerFirstAuditResult['categories']): number => {
  let total = 0;
  (Object.keys(CATEGORY_WEIGHTS) as Array<keyof typeof CATEGORY_WEIGHTS>).forEach((key) => {
    total += categories[key].score * CATEGORY_WEIGHTS[key];
  });
  return Math.round(total);
};

// ================================================================
// SCORE LABEL HELPER
// ================================================================

const scoreToLabel = (score: number): string => {
  if (score >= 80) return 'Excellent';
  if (score >= 60) return 'Bon';
  if (score >= 40) return 'Moyen';
  if (score >= 20) return 'Faible';
  return 'Critique';
};

// ================================================================
// DETERMINISTIC PSEUDO-RANDOM HELPER
// ================================================================

const seededScore = (seed: number, offset: number, min: number = 20, max: number = 85): number => {
  // Simple hash-like deterministic value based on seed + offset
  const raw = ((seed * 31 + offset * 17 + 7) * 13) % 1000;
  return min + Math.round((raw / 1000) * (max - min));
};

// ================================================================
// FALLBACK SIMULATION
// ================================================================

const fallbackSimulation = async (url: string, brandName?: string): Promise<AnswerFirstAuditResult> => {
  await new Promise(resolve => setTimeout(resolve, 2500));

  let hostname: string;
  try {
    hostname = new URL(url).hostname;
  } catch {
    hostname = url;
  }
  const brand = brandName || hostname;
  const seed = url.length + hostname.length;

  const answerFirstScore = seededScore(seed, 1);
  const schemaOrgScore = seededScore(seed, 2);
  const faqStructureScore = seededScore(seed, 3);
  const semanticHtmlScore = seededScore(seed, 4);
  const contentFreshnessScore = seededScore(seed, 5);
  const metaOptimizationScore = seededScore(seed, 6);

  const categories: AnswerFirstAuditResult['categories'] = {
    answerFirst: {
      score: answerFirstScore,
      label: scoreToLabel(answerFirstScore),
      details: answerFirstScore >= 60
        ? `${brand} fournit une reponse relativement directe dans les premiers paragraphes, mais elle pourrait etre plus concise et placee dans les 100 premiers mots.`
        : `La page de ${brand} ne fournit pas de reponse directe dans les 100 premiers mots. Le contenu est trop introductif avant d'atteindre l'information cle.`,
      tips: answerFirstScore >= 60
        ? [
            "Raccourcir l'introduction pour placer la reponse cle des la premiere phrase",
            "Utiliser un format 'Definition Box' en haut de page avec la reponse concise",
            "Ajouter un <p> de reponse directe avant le sommaire"
          ]
        : [
            "Restructurer le contenu pour placer la reponse principale dans les 50 premiers mots",
            "Eliminer les paragraphes d'introduction generiques avant la reponse",
            "Adopter le format 'inverted pyramid' : conclusion d'abord, details ensuite",
            "Ajouter un encart 'En bref' ou 'Reponse rapide' tout en haut de la page"
          ]
    },
    schemaOrg: {
      score: schemaOrgScore,
      label: scoreToLabel(schemaOrgScore),
      details: schemaOrgScore >= 60
        ? `Des donnees structurees JSON-LD sont presentes sur ${hostname} mais pourraient etre enrichies avec des types plus specifiques (FAQPage, HowTo, Article).`
        : `Peu ou pas de donnees structurees JSON-LD detectees sur ${hostname}. Les moteurs IA ne trouvent pas de donnees structurees exploitables.`,
      tips: schemaOrgScore >= 60
        ? [
            "Ajouter le schema FAQPage pour les sections questions/reponses",
            "Enrichir le schema Organization avec sameAs, logo et contactPoint",
            "Valider les donnees structurees avec le Rich Results Test de Google"
          ]
        : [
            "Implementer un schema JSON-LD Organization sur toutes les pages",
            "Ajouter un schema Article ou WebPage avec datePublished et dateModified",
            "Creer un schema FAQPage pour chaque section de questions/reponses",
            "Utiliser le schema BreadcrumbList pour la navigation",
            "Tester l'implementation sur search.google.com/test/rich-results"
          ]
    },
    faqStructure: {
      score: faqStructureScore,
      label: scoreToLabel(faqStructureScore),
      details: faqStructureScore >= 60
        ? `Des sections FAQ sont presentes sur ${hostname}. Le format Q&A est partiellement structure mais pourrait etre ameliore avec des balises semantiques.`
        : `Aucune section FAQ structuree detectee sur ${hostname}. Les IA ne trouvent pas de paires question/reponse claires a extraire.`,
      tips: faqStructureScore >= 60
        ? [
            "Ajouter le balisage Schema.org FAQPage aux sections FAQ existantes",
            "Utiliser des <details>/<summary> pour les questions accordeon",
            "Formuler chaque question comme une vraie requete utilisateur"
          ]
        : [
            "Creer une section FAQ dediee avec au moins 5-8 questions frequentes",
            "Structurer chaque Q&A avec <h3> pour la question et <p> pour la reponse",
            "Ajouter le schema FAQPage en JSON-LD",
            "Utiliser des questions naturelles ('Comment...', 'Pourquoi...', 'Qu'est-ce que...')",
            "Placer les FAQ pres du contenu principal, pas uniquement en bas de page"
          ]
    },
    semanticHtml: {
      score: semanticHtmlScore,
      label: scoreToLabel(semanticHtmlScore),
      details: semanticHtmlScore >= 60
        ? `${hostname} utilise certaines balises semantiques HTML5 (<article>, <section>) mais manque de precision dans la hierarchie des headings et l'utilisation de <details>, <cite>.`
        : `Le HTML de ${hostname} manque de semantique. Peu de balises HTML5 structurantes sont utilisees, rendant le contenu difficile a parser par les IA.`,
      tips: semanticHtmlScore >= 60
        ? [
            "Remplacer les <div> generiques par <article>, <section>, <aside> quand pertinent",
            "Ajouter <cite> pour les sources et references",
            "Utiliser <details>/<summary> pour le contenu accordeon"
          ]
        : [
            "Envelopper le contenu principal dans une balise <article>",
            "Utiliser <section> pour chaque bloc thematique avec un <h2> ou <h3>",
            "Ajouter <nav> pour les menus de navigation et les sommaires",
            "Implementer <details>/<summary> pour les FAQ et contenus depliables",
            "Ajouter <time datetime='...'> pour les dates de publication"
          ]
    },
    contentFreshness: {
      score: contentFreshnessScore,
      label: scoreToLabel(contentFreshnessScore),
      details: contentFreshnessScore >= 60
        ? `Le contenu de ${hostname} semble relativement a jour mais le schema dateModified n'est pas toujours present pour signaler les mises a jour recentes.`
        : `Le contenu de ${hostname} ne semble pas regulierement mis a jour. Aucune indication de dateModified ou de fraicheur du contenu pour les IA.`,
      tips: contentFreshnessScore >= 60
        ? [
            "Ajouter la propriete dateModified dans le schema Article/WebPage",
            "Afficher visuellement la date de derniere mise a jour sur la page",
            "Planifier une revue trimestrielle du contenu principal"
          ]
        : [
            "Ajouter datePublished et dateModified dans le schema JSON-LD",
            "Mettre a jour le contenu au moins tous les 3-6 mois",
            "Afficher clairement 'Derniere mise a jour : [date]' sur chaque page",
            "Creer un calendrier editorial pour maintenir le contenu frais",
            "Ajouter une section 'Actualites' ou 'Blog' avec du contenu recent"
          ]
    },
    metaOptimization: {
      score: metaOptimizationScore,
      label: scoreToLabel(metaOptimizationScore),
      details: metaOptimizationScore >= 60
        ? `Les meta tags de ${hostname} sont presents mais la meta description ne suit pas le format Answer-First. Le canonical et robots sont correctement configures.`
        : `Les meta tags de ${hostname} sont incomplets ou non optimises pour les moteurs de reponse IA. La meta description ne contient pas de reponse directe.`,
      tips: metaOptimizationScore >= 60
        ? [
            "Reformuler la meta description pour commencer par la reponse directe",
            "S'assurer que chaque page a un canonical unique",
            "Verifier que robots.txt n'empeche pas l'indexation IA (Googlebot, GPTBot)"
          ]
        : [
            "Rediger chaque meta description en format Answer-First (reponse directe dans les 60 premiers caracteres)",
            "Ajouter une balise canonical sur toutes les pages",
            "Verifier que robots.txt autorise GPTBot, Google-Extended et Anthropic",
            "Ajouter les meta tags og:title, og:description, og:type",
            "S'assurer que le <title> contient la question cible et la reponse concise"
          ]
    }
  };

  const globalScore = computeGlobalScore(categories);

  // Build top recommendations from lowest-scoring categories
  const sortedCategories = (Object.entries(categories) as [keyof typeof categories, CategoryResult][])
    .sort((a, b) => a[1].score - b[1].score);

  const topRecommendations = sortedCategories.slice(0, 3).map(([key, cat]) => {
    return cat.tips[0];
  });

  const summary = globalScore >= 70
    ? `${brand} presente un bon niveau de citabilite IA avec un score global de ${globalScore}/100. Des optimisations ciblees sur ${sortedCategories[0][1].label === 'Faible' || sortedCategories[0][1].label === 'Critique' ? 'les donnees structurees et le contenu Answer-First' : 'quelques aspects techniques'} permettraient d'atteindre l'excellence.`
    : globalScore >= 45
      ? `${brand} a un niveau de citabilite IA moyen (${globalScore}/100). Les IA peuvent extraire certaines informations mais le contenu n'est pas optimise pour etre cite en priorite. Des actions sur la structure FAQ, le Schema.org et le format Answer-First sont recommandees.`
      : `${brand} a un faible score de citabilite IA (${globalScore}/100). Le contenu n'est pas structure pour etre extrait par les moteurs de reponse IA. Une refonte de la strategie de contenu est necessaire : reponses directes, donnees structurees et balisage semantique.`;

  return {
    globalScore,
    url,
    categories,
    summary,
    topRecommendations
  };
};

