const buildResponseSchema = (): Schema => {
  const categorySchema: Schema = {
    type: Type.OBJECT,
    properties: {
      score: { type: Type.NUMBER, description: "Score de 0 a 100" },
      label: { type: Type.STRING, description: "Label qualitatif : Critique, Faible, Moyen, Bon, Excellent" },
      details: { type: Type.STRING, description: "Explication detaillee de l'evaluation pour cette categorie" },
      tips: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Liste de conseils actionables pour ameliorer cette categorie"
      }
    },
    required: ["score", "label", "details", "tips"]
  };

  return {
    type: Type.OBJECT,
    properties: {
      globalScore: { type: Type.NUMBER, description: "Score global de citabilite IA de 0 a 100 (moyenne ponderee)" },
      summary: { type: Type.STRING, description: "Resume global de l'audit en 2-3 phrases" },
      topRecommendations: {
        type: Type.ARRAY,
        items: { type: Type.STRING },
        description: "Top 3-5 recommandations prioritaires"
      },
      categories: {
        type: Type.OBJECT,
        properties: {
          answerFirst: categorySchema,
          schemaOrg: categorySchema,
          faqStructure: categorySchema,
          semanticHtml: categorySchema,
          contentFreshness: categorySchema,
          metaOptimization: categorySchema,
        },
        required: ["answerFirst", "schemaOrg", "faqStructure", "semanticHtml", "contentFreshness", "metaOptimization"]
      }
    },
    required: ["globalScore", "summary", "topRecommendations", "categories"]
  };
};

