export const auditAnswerFirst = async (url: string, brandName?: string): Promise<AnswerFirstAuditResult> => {
  const apiKey = getApiKey();

  if (!apiKey) {
    console.warn("API_KEY not found or process.env unavailable, using simulation.");
    return fallbackSimulation(url, brandName);
  }

  try {
    const ai = new GoogleGenAI({ apiKey });

    const userPrompt = `
      Audite la citabilite IA de cette URL :

      URL : ${url}
      ${brandName ? `MARQUE : ${brandName}` : ''}

      Analyse le contenu de la page et evalue chaque categorie selon les criteres definis.
      Le score global doit etre la moyenne ponderee :
      - answerFirst: 25%
      - schemaOrg: 20%
      - faqStructure: 15%
      - semanticHtml: 15%
      - contentFreshness: 10%
      - metaOptimization: 15%

      Reponds au format JSON strict selon le schema fourni.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: userPrompt,
      config: {
        systemInstruction: AUDIT_SYSTEM_PROMPT,
        responseMimeType: 'application/json',
        responseSchema: buildResponseSchema(),
        temperature: 0.3,
      }
    });

    let output = response.text;
    if (!output) {
      throw new Error("Empty response from AI");
    }

    // Clean up potentially leaked markdown fences despite JSON mode
    output = output.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

    const parsed = JSON.parse(output);

    return {
      globalScore: parsed.globalScore,
      url,
      categories: {
        answerFirst: parsed.categories.answerFirst,
        schemaOrg: parsed.categories.schemaOrg,
        faqStructure: parsed.categories.faqStructure,
        semanticHtml: parsed.categories.semanticHtml,
        contentFreshness: parsed.categories.contentFreshness,
        metaOptimization: parsed.categories.metaOptimization,
      },
      summary: parsed.summary,
      topRecommendations: parsed.topRecommendations || [],
    };

  } catch (error) {
    console.error("Answer-First Audit failed:", error);
    return fallbackSimulation(url, brandName);
  }
};
